@Transactional
public boolean deletePatrimonio(UUID id) {
    Optional<PatrimonioModel> patrimonioO = patrimonioRepository.findById(id);
    if (patrimonioO.isEmpty()) {
        return false;
    }
    patrimonioRepository.delete(patrimonioO.get());
    return true;
}

